def update_account_balances(transactions):
    """
    Updates account balances based on a list of transactions.

    Args:
        transactions: A list of dictionaries containing transaction details.

    Returns:
        A dictionary of updated account balances.
    """

    accounts = {}

    for transaction in transactions:
        account = transaction['account']
        amount = transaction['amount']

        if account not in accounts:
            accounts[account] = 0

        accounts[account] += amount

    return accounts